// generar_246_medicamentos_fix_editar_novedad.js
// CHIQUI Entre Señales — Medicamentos: fix estado, edición y novedad
//
// Tres arreglos en un solo paquete:
//
// 1) BUG estado "Activo" a pesar de tener fecha_fin pasada.
//    La tarjeta de medicamento leía med.estado desde la base, pero ese
//    campo nunca se actualizaba solo. Fix: el estado ahora se DERIVA
//    en el render — solo "Activo" si estado='activo' Y (no tiene
//    fecha_fin o fecha_fin >= hoy). Si la fecha ya pasó, se muestra
//    "Finalizado" aunque en la base siga como activo.
//
// 2) EDICIÓN de medicamentos (faltaba, solo había insert).
//    Se agrega el botón ⋮ en cada tarjeta (mismo patrón de vacunas y
//    antiparasitarios) → menú con "Editar" y "Eliminar". Al editar,
//    el modal precarga los campos y guarda con UPDATE. Si el usuario
//    borra fecha_fin, vuelve a activo. Título del modal cambia a
//    "🩹 Editar medicamento" cuando corresponde.
//
// 3) NOVEDAD "¿Le diste el medicamento?" en el dashboard.
//    Si hay medicamentos activos (estado derivado) y el registro de
//    hoy NO marca "medicamento_hoy", aparece una novedad efímera con
//    la ilustración Chiqui medicamentos que dice:
//      💊 ¿Ya le diste el medicamento a Luna? (Rimadyl · 1 vez al día)
//    Con acción "💊 Marcar en el registro" que lleva al registro
//    diario. Si el usuario cierra sin marcarlo, reaparece al volver
//    al dashboard (efímera, como la de "aún no registré"). Los
//    nombres de todos los medicamentos activos van listados; la
//    frecuencia se muestra solo si todos comparten la misma.
//
// Prioridad en la cola: se ubica en el 5° lugar (tras estado del
// registro, antes de seguimientos): 1 cumpleaños · 2 aniversario ·
// 3 fechas especiales · 4 estado del registro · 5 MEDICAMENTO · 6
// seguimientos · 7 racha · 8 recordatorio inteligente · 9 mensaje
// positivo · 10 notificaciones.
//
// No hay SQL: usa el campo medicamento_hoy que ya existe en
// registros_diarios.
//
// Uso:
//   node generar_246_medicamentos_fix_editar_novedad.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/prevencion/page.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
  {
    ruta: "components/DashboardContenido.tsx",
    base64: ""
  },
  {
    ruta: "components/Novedades.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 4 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
